// ErrBlobNotFound is returned when a requested path does not resolve to
// a blob at the given SHA. A present-but-non-blob entry (tree,
// submodule, symlink with no target blob) produces the same sentinel:
// callers treat the path as missing.
var ErrBlobNotFound = errors.New("git: blob not found")

// ErrShaNotInCache is returned when a commit SHA is not present in the
// local cache. Materialize is responsible for populating the cache;
// this sentinel surfaces to help tests and higher layers distinguish
// "cache miss" from a genuine read error.
var ErrShaNotInCache = errors.New("git: sha not in cache")

// TreeEntry names a single blob reachable from a commit tree.
//
// Path is the POSIX-style forward-slash path from the tree root.
// Mode mirrors the git file mode (`100644`, `100755`, `120000` for a
// symlink). Size is the blob's uncompressed size.
//
// Symlinks are returned with Mode == 0o120000 and the blob content is
// the link target. Callers upstream decide whether to follow them;
// agent-sync's IR decoder treats symlinks as opaque blobs.
type TreeEntry struct {
	Path string
	Mode uint32
	Size int64
	Hash string
}

// Repository wraps a materialized bare clone so the rest of agent-sync can
// read trees and blobs without importing go-git directly.
//
// Instances are cheap to construct but hold an open object store, so
// callers should Close them when done. Repository methods are safe for
// concurrent read-only use.
type Repository struct {
	path string
	repo *gogit.Repository
}

// Open attaches to the bare clone at repoPath. The directory must already
// have been populated by Materialize; Open does not clone.
func Open(repoPath string) (*Repository, error) {
	r, err := gogit.PlainOpen(repoPath)
	if err != nil {
		return nil, fmt.Errorf("git: open %q: %w", repoPath, err)
	}
	return &Repository{path: repoPath, repo: r}, nil
}

// Close releases the underlying object store handles. Safe to call
// multiple times.
func (r *Repository) Close() error {
	// go-git 5.17 PlainOpen returns an in-memory wrapper with no explicit
	// close; nothing to release today. The method exists so a future
	// go-git version that grows a Close() can be wired in without a
	// caller-visible break.
	return nil
}

// Path returns the filesystem path the repository was opened at.
func (r *Repository) Path() string {
	return r.path
}

// HasCommit reports whether the given 40-char SHA resolves to a commit
// object in the local store. It returns [ErrShaNotInCache] as a clean
// sentinel for callers that need to branch on cache-miss.
func (r *Repository) HasCommit(sha string) (bool, error) {
	if !shaPattern.MatchString(strings.ToLower(sha)) {
		return false, fmt.Errorf("git: has-commit: invalid sha %q", sha)
	}
	hash := plumbing.NewHash(sha)
	_, err := r.repo.CommitObject(hash)
	if err == nil {
		return true, nil
	}
	if errors.Is(err, plumbing.ErrObjectNotFound) {
		return false, nil
	}
	return false, fmt.Errorf("git: has-commit %s: %w", sha, err)
}

// ReadTree walks the tree reachable from commitSHA and returns every
// blob entry under it, keyed by POSIX path. Sub-trees are expanded
// recursively; submodule gitlinks are skipped (they are not part of the
// canonical source tree from agent-sync's perspective).
//
// Deterministic order: entries are sorted by Path so callers consuming
// the slice for diffing or hashing get stable results across runs.
func (r *Repository) ReadTree(commitSHA string) ([]TreeEntry, error) {
	sha := strings.ToLower(strings.TrimSpace(commitSHA))
	if !shaPattern.MatchString(sha) {
		return nil, fmt.Errorf("git: read-tree: invalid sha %q", commitSHA)
	}
	commit, err := r.repo.CommitObject(plumbing.NewHash(sha))
	if err != nil {
		if errors.Is(err, plumbing.ErrObjectNotFound) {
			return nil, fmt.Errorf("%w: %s", ErrShaNotInCache, sha)
		}
		return nil, fmt.Errorf("git: read-tree: commit %s: %w", sha, err)
	}
	tree, err := commit.Tree()
	if err != nil {
		return nil, fmt.Errorf("git: read-tree: tree %s: %w", sha, err)
	}

	entries := make([]TreeEntry, 0, 64)
	walker := object.NewTreeWalker(tree, true, nil)
	defer walker.Close()
	for {
		name, entry, err := walker.Next()
		if err != nil {
			if errors.Is(err, io.EOF) {
				break
			}
			return nil, fmt.Errorf("git: read-tree: walk: %w", err)
		}
		// Skip directories (we only report blobs) and submodule gitlinks.
		if !entry.Mode.IsFile() && entry.Mode != 0o120000 {
			continue
		}
		blob, err := r.repo.BlobObject(entry.Hash)
		if err != nil {
			return nil, fmt.Errorf("git: read-tree: blob %s at %s: %w", entry.Hash, name, err)
		}
		entries = append(entries, TreeEntry{
			Path: path.Clean(name),
			Mode: uint32(entry.Mode),
			Size: blob.Size,
			Hash: entry.Hash.String(),
		})
	}
	sortEntries(entries)
	return entries, nil
}

// BlobContent returns the bytes of the blob at relPath in the tree of
// commitSHA. Missing paths, directories, and submodule gitlinks all
// surface as [ErrBlobNotFound].
//
// The caller is responsible for any size limits; BlobContent loads the
// full blob into memory. The IR decoder in unit 7 will wrap this with
// per-concept caps.
func (r *Repository) BlobContent(commitSHA, relPath string) ([]byte, error) {
	sha := strings.ToLower(strings.TrimSpace(commitSHA))
	if !shaPattern.MatchString(sha) {
		return nil, fmt.Errorf("git: blob: invalid sha %q", commitSHA)
	}
	clean := path.Clean("/" + relPath)
	if clean == "/" {
		return nil, fmt.Errorf("%w: empty path", ErrBlobNotFound)
	}
	clean = strings.TrimPrefix(clean, "/")

	commit, err := r.repo.CommitObject(plumbing.NewHash(sha))
	if err != nil {
		if errors.Is(err, plumbing.ErrObjectNotFound) {
			return nil, fmt.Errorf("%w: %s", ErrShaNotInCache, sha)
		}
		return nil, fmt.Errorf("git: blob: commit %s: %w", sha, err)
	}
	tree, err := commit.Tree()
	if err != nil {
		return nil, fmt.Errorf("git: blob: tree %s: %w", sha, err)
	}
	file, err := tree.File(clean)
	if err != nil {
		if errors.Is(err, object.ErrFileNotFound) {
			return nil, fmt.Errorf("%w: %s at %s", ErrBlobNotFound, clean, sha)
		}
		return nil, fmt.Errorf("git: blob: file %q at %s: %w", clean, sha, err)
	}
	rc, err := file.Reader()
	if err != nil {
		return nil, fmt.Errorf("git: blob: reader %q at %s: %w", clean, sha, err)
	}
	defer func() { _ = rc.Close() }()
	buf, err := io.ReadAll(rc)
	if err != nil {
		return nil, fmt.Errorf("git: blob: read %q at %s: %w", clean, sha, err)
	}
	return buf, nil
}

// sortEntries sorts TreeEntries by Path in ascending lexicographic order.
// The ordering is part of ReadTree's public contract.
func sortEntries(entries []TreeEntry) {
	slices.SortFunc(entries, func(a, b TreeEntry) int {
		return strings.Compare(a.Path, b.Path)
	})
}
// Package worktree provides a filesystem-backed implementation of the IR
// decoder's source surface (ir.SourceTree), reading a canonical-layout source
// directly from a workspace's working tree instead of a git object store.
//
// It is the read side of the in-repo / local source kind (canonical.local_dir):
// a workspace can author skills, rules, commands, AGENTS.md, mcp, and plugins
// under a workspace-relative directory (e.g. ".agents") and have agent-sync
// compile them with no git, no clone, and no commit pin.
package worktree

import (
	"errors"
	"fmt"
	"io"
	"io/fs"
	"path"
	"sort"
	"strings"

	"github.com/agent-sync/agent-sync/internal/fsroot"
	"github.com/agent-sync/agent-sync/internal/git"
	"github.com/agent-sync/agent-sync/internal/ir"
)

// Reader satisfies the IR decoder's source surface.
var _ ir.SourceTree = (*Reader)(nil)

// ownedSkillPrefix is the leaf-name prefix agent-sync uses for the skills it
// emits into the shared ".agents/skills" tree (see the Codex adapter). The
// reader skips "skills/agent-sync-*" so the source is never read from its own
// emitted output — this is what keeps a ".agents"-rooted source and an
// ".agents/skills" target stable across repeated syncs. The prefix is
// therefore reserved for outputs and unavailable for authored skill ids.
const ownedSkillPrefix = "agent-sync-"

// maxBlobSize caps a single source file read (4 MiB) as defense-in-depth
// against a pathologically large file in the source tree.
const maxBlobSize = 4 << 20

// ErrSourceMissing is returned when the configured local_dir does not exist.
// Callers map this to a clear "source directory not found" message rather than
// a git-shaped error.
var ErrSourceMissing = errors.New("worktree: source directory does not exist")

// Reader reads a canonical-layout source from a working-tree directory.
// It satisfies ir.SourceTree. The ref argument to ReadTree/BlobContent is
// ignored: a working tree has no commit to address.
type Reader struct {
	root     *fsroot.Root
	localDir string // cleaned, workspace-relative (e.g. ".agents")
}

// NewReader builds a Reader rooted at localDir within the workspace root.
// localDir must be a safe, non-root, workspace-relative path; root is borrowed,
// not owned (the caller closes it).
func NewReader(root *fsroot.Root, localDir string) (*Reader, error) {
	if root == nil {
		return nil, errors.New("worktree: nil workspace root")
	}
	if err := fsroot.ValidateRelPath(localDir); err != nil {
		return nil, fmt.Errorf("worktree: local_dir: %w", err)
	}
	cleaned := path.Clean(localDir)
	if cleaned == "." {
		return nil, errors.New("worktree: local_dir must be a workspace subdirectory, not the root")
	}
	return &Reader{root: root, localDir: cleaned}, nil
}

// ReadTree returns the source tree as a flat list of file entries, with paths
// relative to local_dir so the decoder sees the canonical layout at its root
// (e.g. "skills/foo/SKILL.md"). Directories, symlinks, and other irregular
// files are not emitted, and the owned-output subtree (skills/agent-sync-*) is
// skipped. The ref argument is ignored.
func (r *Reader) ReadTree(_ string) ([]git.TreeEntry, error) {
	info, err := r.root.Stat(r.localDir)
	if err != nil {
		if errors.Is(err, fs.ErrNotExist) {
			return nil, fmt.Errorf("%w: %q", ErrSourceMissing, r.localDir)
		}
		return nil, fmt.Errorf("worktree: stat %q: %w", r.localDir, err)
	}
	if !info.IsDir() {
		return nil, fmt.Errorf("worktree: local_dir %q is not a directory", r.localDir)
	}

	var entries []git.TreeEntry
	if err := r.walk(r.localDir, &entries); err != nil {
		return nil, err
	}
	// Deterministic order — ReadDir order is unspecified, and the decoder's
	// duplicate-id detection is first-seen sensitive.
	sort.Slice(entries, func(i, j int) bool { return entries[i].Path < entries[j].Path })
	return entries, nil
}

// walk recurses through dir (workspace-relative), appending one TreeEntry per
// regular file with its path made relative to local_dir.
func (r *Reader) walk(dir string, out *[]git.TreeEntry) error {
	f, err := r.root.Inner().Open(dir)
	if err != nil {
		return fmt.Errorf("worktree: open %q: %w", dir, err)
	}
	dirents, err := f.ReadDir(-1)
	_ = f.Close()
	if err != nil {
		return fmt.Errorf("worktree: read dir %q: %w", dir, err)
	}

	for _, de := range dirents {
		child := dir + "/" + de.Name()
		if de.IsDir() {
			if r.isOwnedSkillDir(child) {
				continue // emitted output, not source
			}
			if err := r.walk(child, out); err != nil {
				return err
			}
			continue
		}
		info, err := de.Info()
		if err != nil {
			return fmt.Errorf("worktree: stat %q: %w", child, err)
		}
		mode := info.Mode()
		// Never follow or emit symlinks; skip irregular files (devices,
		// sockets, pipes). os.Root already refuses to traverse escaping
		// symlinks; this is defense-in-depth on the listing side.
		if mode&fs.ModeSymlink != 0 || !mode.IsRegular() {
			continue
		}
		rel := strings.TrimPrefix(child, r.localDir+"/")
		*out = append(*out, git.TreeEntry{
			Path: rel,
			Mode: 0o100644,
			Size: info.Size(),
		})
	}
	return nil
}

// isOwnedSkillDir reports whether a workspace-relative directory is one of
// agent-sync's emitted skill outputs in the shared skills tree
// (local_dir/skills/agent-sync-*).
func (r *Reader) isOwnedSkillDir(childWorkspaceRel string) bool {
	rel := strings.TrimPrefix(childWorkspaceRel, r.localDir+"/")
	return strings.HasPrefix(rel, "skills/"+ownedSkillPrefix)
}

// BlobContent returns the bytes of the file at relPath (relative to local_dir,
// as emitted by ReadTree). The ref argument is ignored.
func (r *Reader) BlobContent(_ string, relPath string) ([]byte, error) {
	full := r.localDir + "/" + relPath
	f, err := r.root.Inner().Open(full)
	if err != nil {
		return nil, fmt.Errorf("worktree: open blob %q: %w", full, err)
	}
	defer func() { _ = f.Close() }()
	data, err := io.ReadAll(io.LimitReader(f, maxBlobSize+1))
	if err != nil {
		return nil, fmt.Errorf("worktree: read blob %q: %w", full, err)
	}
	if len(data) > maxBlobSize {
		return nil, fmt.Errorf("worktree: blob %q exceeds %d bytes", full, maxBlobSize)
	}
	return data, nil
}

